        function generateReport() {
            const r = APP.results;
            const isLogScale = APP.config.outcomeType === 'survival' ||
                              (APP.config.outcomeType === 'binary' && APP.config.effectMeasure !== 'RD');

            return `<!DOCTYPE html>
<html>
<head>
    <title>IPD Meta-Analysis Report</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 900px; margin: 0 auto; padding: 2rem; }
        h1 { color: #6366f1; }
        table { width: 100%; border-collapse: collapse; margin: 1rem 0; }
        th, td { padding: 0.5rem; text-align: left; border-bottom: 1px solid #ddd; }
        th { background: #f5f5f5; }
        .stat { display: inline-block; margin: 0.5rem 1rem 0.5rem 0; }
        .stat-value { font-size: 1.5rem; font-weight: bold; color: #6366f1; }
        .stat-label { font-size: 0.8rem; color: #666; }
    </style>
</head>
<body>
    <h1>IPD Meta-Analysis Report</h1>
    <p>Generated: ${new Date().toLocaleString()}</p>

    <h2>Summary</h2>
    <div class="stat">
        <div class="stat-value">${r.studies.length}</div>
        <div class="stat-label">Studies</div>
    </div>
    <div class="stat">
        <div class="stat-value">${APP.data.length}</div>
        <div class="stat-label">Patients</div>
    </div>
    <div class="stat">
        <div class="stat-value">${(isLogScale ? Math.exp(r.pooled.pooled) : r.pooled.pooled).toFixed(2)}</div>
        <div class="stat-label">Pooled ${APP.config.effectMeasure}</div>
    </div>
    <div class="stat">
        <div class="stat-value">${r.pooled.I2.toFixed(1)}%</div>
        <div class="stat-label">I-squared</div>
    </div>

    <h2>Study Results</h2>
    <table>
        <tr><th>Study</th><th>N</th><th>Effect</th><th>95% CI</th><th>Weight</th></tr>
        ${r.studies.map(s => `
            <tr>
                <td>${s.study}</td>
                <td>${s.n}</td>
                <td>${(isLogScale ? Math.exp(s.effect) : s.effect).toFixed(2)}</td>
                <td>${(isLogScale ? Math.exp(s.lower) : s.lower).toFixed(2)} - ${(isLogScale ? Math.exp(s.upper) : s.upper).toFixed(2)}</td>
                <td>${(s.weight * 100).toFixed(1)}%</td>
            </tr>
        `).join('')}
    </table>

    <h2>Heterogeneity</h2>
    <p>Q = ${r.pooled.Q.toFixed(2)}, df = ${r.pooled.df}, p = ${r.pooled.pQ.toFixed(4)}</p>
    <p>I² = ${r.pooled.I2.toFixed(1)}%, τ² = ${r.pooled.tau2.toFixed(4)}</p>

    <h2>Methods</h2>
    <p>Analysis type: ${APP.config.analysisApproach}</p>
    <p>Outcome: ${APP.config.outcomeType}</p>
    <p>Effect measure: ${APP.config.effectMeasure}</p>
    <p>Heterogeneity estimator: ${APP.config.reMethod}</p>
    ${APP.config.useHKSJ ? '<p>Hartung-Knapp-Sidik-Jonkman adjustment applied</p>' : ''}

    <hr>
    <p><em>Generated by IPD Meta-Analysis Pro</em></p>

    <!-- ====================================================================== -->
    <!-- METHODOLOGY DISCLAIMER - Added per Research Synthesis Methods Review -->
    <!-- ====================================================================== -->
    <div id="methodologyDisclaimer" style="display:none; position:fixed; bottom:20px; right:20px;
         max-width:400px; background:var(--bg-card); border:1px solid var(--border-color);
         border-radius:12px; padding:16px; box-shadow:var(--shadow-lg); z-index:1000;">
        <button onclick="this.parentElement.style.display='none'"
                style="position:absolute;top:8px;right:8px;background:none;border:none;
                       color:var(--text-muted);cursor:pointer;font-size:1.2rem;">&times;</button>
        <h4 style="margin:0 0 8px 0;color:var(--accent-primary);">Methodology Note</h4>
        <p style="font-size:0.85rem;color:var(--text-secondary);margin:0;">
            This browser-based tool provides <strong>approximate</strong> implementations
            of statistical methods for educational and exploratory purposes.
            For publication-quality analyses, validate results against R (metafor, lme4, survival)
            or Stata reference implementations.
        </p>
        <p style="font-size:0.75rem;color:var(--text-muted);margin:8px 0 0 0;">
            <a href="#" onclick="showAllCitations();return false;" style="color:var(--accent-info);">
                View methodological references
            </a>
        </p>
    </div>
    <scr` + `ipt>
        // Show disclaimer on first visit
        if (!localStorage.getItem('disclaimerSeen')) {
            setTimeout(function() {
                document.getElementById('methodologyDisclaimer').style.display = 'block';
                localStorage.setItem('disclaimerSeen', 'true');
            }, 2000);
        }
    </scr` + `ipt>

</body>
</html>`;
        }

        function exportResults(format) {
            if (!APP.results) {
                alert('Please run analysis first');
                return;
            }

            if (format === 'csv') {
                const csv = ['Study,N,Events,Effect,SE,Lower,Upper,Weight,P-value',
                    ...APP.results.studies.map(s =>
                        `${s.study},${s.n},${s.events},${s.effect.toFixed(4)},${s.se.toFixed(4)},${s.lower.toFixed(4)},${s.upper.toFixed(4)},${s.weight.toFixed(4)},${s.p.toFixed(6)}`
                    )
                ].join('\n');

                const blob = new Blob([csv], { type: 'text/csv' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'meta_analysis_results.csv';
                a.click();
            } else {
                exportAnalysis();
            }
        }

        function downloadForest(format) {
            const canvas = document.getElementById('forestPlot');
            downloadCanvas(canvas, 'forest_plot', format);
        }

        function downloadFunnel(format) {
            const canvas = document.getElementById('funnelPlot');
            downloadCanvas(canvas, 'funnel_plot', format);
        }

        function downloadNetwork(format) {
            const canvas = document.getElementById('networkPlot');
            downloadCanvas(canvas, 'network_plot', format);
        }

        function downloadCanvas(canvas, name, format) {
            if (format === 'png') {
                const link = document.createElement('a');
                link.download = `${name}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();
            } else {
                // For SVG, we'd need to recreate with SVG renderer
                alert('SVG export coming soon. PNG downloaded instead.');
                downloadCanvas(canvas, name, 'png');
            }
        }

        function clearData() {
            APP.data = null;
            APP.variables = [];
            APP.results = null;
            document.getElementById('dataPreviewCard').style.display = 'none';
            document.getElementById('analysisSettingsCard').style.display = 'none';
        }

        function editData() {
            alert('Data editor coming soon. For now, edit your CSV and re-upload.');
        }

        function toggleContour() {
            // Toggle contour on funnel plot
            const canvas = document.getElementById('funnelPlot');
            if (APP.results) {
                const effects = APP.results.studies.map(s => s.effect);
                const ses = APP.results.studies.map(s => s.se);
                Plots.drawFunnel(canvas, effects, ses, APP.results.pooled.pooled, { showContour: true });
            }
        }

        function runSelectionModel() {
            alert('Selection models (3PSM, Copas) coming soon.');
        }

        // Build network from actual IPD data
        function buildNetworkFromData() {
            if (!APP.data || APP.data.length === 0) return;

            // Get unique treatments
            const treatmentVar = APP.config.treatmentVar || 'treatment_name';
            const studyVar = APP.config.studyVar || 'study_id';

            const treatments = [...new Set(APP.data.map(d => d[treatmentVar] || d.treatment_name))];
            const studies = [...new Set(APP.data.map(d => d[studyVar]))];

            // Build nodes (treatments)
            const treatmentCounts = {};
            treatments.forEach(t => {
                treatmentCounts[t] = APP.data.filter(d => (d[treatmentVar] || d.treatment_name) === t).length;
            });

            const maxCount = Math.max(...Object.values(treatmentCounts));
            const nodes = treatments.map((t, i) => ({
                id: t,
                label: t.length > 15 ? t.substring(0, 12) + '...' : t,
                size: 20 + (treatmentCounts[t] / maxCount) * 40
            }));

            // Build edges (comparisons within studies)
            const edgeMap = {};
            studies.forEach(study => {
                const studyData = APP.data.filter(d => d[studyVar] === study);
                const studyTreatments = [...new Set(studyData.map(d => d[treatmentVar] || d.treatment_name))];

                // Create edges between all treatments in this study
                for (let i = 0; i < studyTreatments.length; i++) {
                    for (let j = i + 1; j < studyTreatments.length; j++) {
                        const t1 = studyTreatments[i];
                        const t2 = studyTreatments[j];
                        const key = [t1, t2].sort().join('|');

                        if (!edgeMap[key]) {
                            edgeMap[key] = { from: t1, to: t2, weight: 0, studies: [] };
                        }
                        edgeMap[key].weight++;
                        edgeMap[key].studies.push(study);
                    }
                }
            });

            const edges = Object.values(edgeMap).map(e => ({
                ...e,
                label: String(e.weight)
            }));

            // Draw the network
            const canvas = document.getElementById('networkPlot');
            if (canvas) {
                Plots.drawNetwork(canvas, nodes, edges);
            }

            // Update network statistics
            document.getElementById('networkNodes').textContent = nodes.length;
            document.getElementById('networkEdges').textContent = edges.length;

            // Check if network is connected (simple check)
            const connected = edges.length >= nodes.length - 1 ? 'Yes' : 'No';
            document.getElementById('networkConnected').textContent = connected;

            // Update network table
            const netBody = document.getElementById('networkTableBody');
            if (netBody && edges.length > 0) {
                netBody.innerHTML = edges.map(e => {
                    const fromData = APP.data.filter(d => (d[treatmentVar] || d.treatment_name) === e.from);
                    const toData = APP.data.filter(d => (d[treatmentVar] || d.treatment_name) === e.to);
                    const totalN = fromData.length + toData.length;
                    const eventVar = APP.config.eventVar || 'event';
                    const events = fromData.filter(d => d[eventVar] === 1).length + toData.filter(d => d[eventVar] === 1).length;

                    return `<tr>
                        <td>${e.from} vs ${e.to}</td>
                        <td>${e.weight}</td>
                        <td>${totalN}</td>
                        <td>${events}</td>
                        <td><span class="badge badge-success">Yes</span></td>
                    </tr>`;
                }).join('');
            }

            return { nodes, edges, treatments };
        }

        
    // ============================================================================
    // NETWORK META-ANALYSIS - IMPORTANT LIMITATIONS (Editorial Revision)
    // ============================================================================
    // This implementation uses the Bucher method for indirect comparisons.
    //
    // LIMITATIONS vs. full NMA (R netmeta, Stata network):
    //   - Indirect comparisons only (not multivariate NMA model)
    //   - No consistency equations for closed loops
    //   - Cannot estimate all pairwise comparisons simultaneously
    //   - No design-by-treatment interaction model
    //   - SUCRA scores are approximate
    //
    // For rigorous network meta-analysis, use:
    //   - R: netmeta::netmeta(), gemtc::mtc.model()
    //   - Stata: network meta, mvmeta
    //   - WinBUGS/OpenBUGS for Bayesian NMA
    // ============================================================================

// Network Meta-Analysis (Bucher method for indirect comparisons)
        function runNetworkMetaAnalysis() {
            const network = buildNetworkFromData();
            if (!network || network.treatments.length < 3) {
                showNotification('Network meta-analysis requires at least 3 treatments', 'warning');
                return null;
            }

            const { nodes, edges, treatments } = network;

            // Calculate direct estimates for each comparison
            const directEstimates = {};
            const treatmentVar = APP.config.treatmentVar || 'treatment_name';
            const studyVar = APP.config.studyVar || 'study_id';
            const eventVar = APP.config.eventVar || 'event';

            edges.forEach(edge => {
                const t1Data = APP.data.filter(d => (d[treatmentVar] || d.treatment_name) === edge.from);
                const t2Data = APP.data.filter(d => (d[treatmentVar] || d.treatment_name) === edge.to);

                // Calculate log OR or log HR
                const e1 = t1Data.filter(d => d[eventVar] === 1).length;
                const n1 = t1Data.length;
                const e2 = t2Data.filter(d => d[eventVar] === 1).length;
                const n2 = t2Data.length;

                // Log odds ratio with continuity correction
                const logOR = Math.log(((e1 + 0.5) * (n2 - e2 + 0.5)) / ((e2 + 0.5) * (n1 - e1 + 0.5)));
                const varLogOR = 1/(e1+0.5) + 1/(n1-e1+0.5) + 1/(e2+0.5) + 1/(n2-e2+0.5);

                directEstimates[`${edge.from}|${edge.to}`] = {
                    logEffect: logOR,
                    variance: varLogOR,
                    se: Math.sqrt(varLogOR),
                    studies: edge.weight
                };
            });

            // Calculate SUCRA scores (simplified)
            const sucraScores = {};
            treatments.forEach(t => {
                // Count wins (lower effect is better for harmful outcomes)
                let wins = 0;
                let comparisons = 0;
                treatments.forEach(other => {
                    if (t === other) return;
                    const key1 = `${t}|${other}`;
                    const key2 = `${other}|${t}`;
                    const est = directEstimates[key1] || directEstimates[key2];
                    if (est) {
                        comparisons++;
                        // If t is better (lower log effect when t is first)
                        if (directEstimates[key1] && est.logEffect < 0) wins++;
                        if (directEstimates[key2] && est.logEffect > 0) wins++;
                    }
                });
                sucraScores[t] = comparisons > 0 ? (wins / comparisons) * 100 : 50;
            });

            // Update ranking table
            const rankBody = document.getElementById('rankingTableBody');
            if (rankBody) {
                const sorted = treatments.sort((a, b) => sucraScores[b] - sucraScores[a]);
                rankBody.innerHTML = sorted.map((t, i) => {
                    const pScore = sucraScores[t] / 100;
                    const meanRank = 1 + (1 - pScore) * (treatments.length - 1);
                    const pBest = i === 0 ? Math.round(pScore * 100 / 2) : Math.round((1 - i / treatments.length) * 20);
                    const pWorst = i === treatments.length - 1 ? Math.round((1 - pScore) * 100 / 2) : Math.round(i / treatments.length * 15);

                    return `<tr>
                        <td><strong>${t}</strong></td>
                        <td>${sucraScores[t].toFixed(1)}%</td>
                        <td>${pScore.toFixed(2)}</td>
                        <td>${meanRank.toFixed(1)}</td>
                        <td>${pBest}%</td>
                        <td>${pWorst}%</td>
                    </tr>`;
                }).join('');
            }

            return { directEstimates, sucraScores, network };
        }

        // ============================================================
        // MACHINE LEARNING-ASSISTED SUBGROUP DETECTION
        // ============================================================

        // Decision tree for treatment effect heterogeneity
        class DecisionTree {
            constructor(maxDepth = 4, minSamples = 20) {
                this.maxDepth = maxDepth;
                this.minSamples = minSamples;
                this.tree = null;
            }

            // Calculate treatment effect in a subset
            calculateTreatmentEffect(data, treatmentVar, outcomeVar) {
                const treated = data.filter(d => d[treatmentVar] === 1);
                const control = data.filter(d => d[treatmentVar] === 0);

                if (treated.length < 5 || control.length < 5) return null;

                const meanTreated = treated.reduce((s, d) => s + (d[outcomeVar] || 0), 0) / treated.length;
                const meanControl = control.reduce((s, d) => s + (d[outcomeVar] || 0), 0) / control.length;

                return meanTreated - meanControl;
            }

            // Find best split for a node
            findBestSplit(data, covariates, treatmentVar, outcomeVar) {
                let bestGain = 0;
                let bestSplit = null;

                const baseEffect = this.calculateTreatmentEffect(data, treatmentVar, outcomeVar);
                if (baseEffect === null) return null;

                covariates.forEach(cov => {
                    const values = [...new Set(data.map(d => d[cov]))].filter(v => v != null);

                    if (typeof data[0][cov] === 'number') {
                        // Numeric: try quantile splits
                        const sortedVals = values.sort((a, b) => a - b);
                        const quartiles = [0.25, 0.5, 0.75].map(q => sortedVals[Math.floor(sortedVals.length * q)]);

                        quartiles.forEach(threshold => {
                            const left = data.filter(d => d[cov] <= threshold);
                            const right = data.filter(d => d[cov] > threshold);

                            if (left.length >= this.minSamples && right.length >= this.minSamples) {
                                const leftEffect = this.calculateTreatmentEffect(left, treatmentVar, outcomeVar);
                                const rightEffect = this.calculateTreatmentEffect(right, treatmentVar, outcomeVar);

                                if (leftEffect !== null && rightEffect !== null) {
                                    // Information gain based on effect heterogeneity
                                    const gain = Math.abs(leftEffect - rightEffect);
                                    if (gain > bestGain) {
                                        bestGain = gain;
                                        bestSplit = { covariate: cov, threshold, type: 'numeric',
                                            leftEffect, rightEffect, leftN: left.length, rightN: right.length };
                                    }
                                }
                            }
                        });
                    } else {
                        // Categorical: split on each value
                        values.forEach(val => {
                            const left = data.filter(d => d[cov] === val);
                            const right = data.filter(d => d[cov] !== val);

                            if (left.length >= this.minSamples && right.length >= this.minSamples) {
                                const leftEffect = this.calculateTreatmentEffect(left, treatmentVar, outcomeVar);
                                const rightEffect = this.calculateTreatmentEffect(right, treatmentVar, outcomeVar);

                                if (leftEffect !== null && rightEffect !== null) {
                                    const gain = Math.abs(leftEffect - rightEffect);
                                    if (gain > bestGain) {
                                        bestGain = gain;
                                        bestSplit = { covariate: cov, value: val, type: 'categorical',
                                            leftEffect, rightEffect, leftN: left.length, rightN: right.length };
                                    }
                                }
                            }
                        });
                    }
                });

                return bestSplit;
            }

            // Build tree recursively
            buildTree(data, covariates, treatmentVar, outcomeVar, depth = 0) {
                const effect = this.calculateTreatmentEffect(data, treatmentVar, outcomeVar);

                if (depth >= this.maxDepth || data.length < this.minSamples * 2 || effect === null) {
                    return { type: 'leaf', effect, n: data.length };
                }

                const split = this.findBestSplit(data, covariates, treatmentVar, outcomeVar);

                if (!split || split.leftEffect === null || split.rightEffect === null) {
                    return { type: 'leaf', effect, n: data.length };
                }

                let leftData, rightData;
                if (split.type === 'numeric') {
                    leftData = data.filter(d => d[split.covariate] <= split.threshold);
                    rightData = data.filter(d => d[split.covariate] > split.threshold);
                } else {
                    leftData = data.filter(d => d[split.covariate] === split.value);
                    rightData = data.filter(d => d[split.covariate] !== split.value);
                }

                return {
                    type: 'node',
                    split: split,
                    left: this.buildTree(leftData, covariates, treatmentVar, outcomeVar, depth + 1),
                    right: this.buildTree(rightData, covariates, treatmentVar, outcomeVar, depth + 1)
                };
            }

            fit(data, covariates, treatmentVar, outcomeVar) {
                this.tree = this.buildTree(data, covariates, treatmentVar, outcomeVar);
                return this;
            }

            getSubgroups(node = this.tree, path = []) {
                const subgroups = [];

                if (node.type === 'leaf') {
                    subgroups.push({ path: path.join(' AND '), effect: node.effect, n: node.n });
                } else {
                    const split = node.split;
                    let leftCond, rightCond;

                    if (split.type === 'numeric') {
                        leftCond = `${split.covariate} <= ${split.threshold.toFixed(1)}`;
                        rightCond = `${split.covariate} > ${split.threshold.toFixed(1)}`;
                    } else {
                        leftCond = `${split.covariate} = '${split.value}'`;
                        rightCond = `${split.covariate} != '${split.value}'`;
                    }

                    subgroups.push(...this.getSubgroups(node.left, [...path, leftCond]));
                    subgroups.push(...this.getSubgroups(node.right, [...path, rightCond]));
                }

                return subgroups;
            }
        }

        // Run ML-assisted subgroup detection
        function runMLSubgroupDetection() {
            if (!APP.data || APP.data.length === 0) {
                showNotification('Please load data first', 'warning');
                return;
            }

            const treatmentVar = APP.config.treatmentVar || 'treatment';
            const outcomeVar = APP.config.eventVar || 'event';

            // Get numeric and categorical covariates for subgroup analysis
            const excludeVars = [treatmentVar, outcomeVar, 'study_id', 'patient_id', 'treatment_name', 'time_months'];
            const covariates = Object.keys(APP.data[0]).filter(k => !excludeVars.includes(k));

            if (covariates.length === 0) {
                showNotification('No covariates available for subgroup analysis', 'warning');
                return;
            }

            // Build decision tree
            const tree = new DecisionTree(3, 30);
            tree.fit(APP.data, covariates, treatmentVar, outcomeVar);

            const subgroups = tree.getSubgroups();

            // Sort by effect magnitude
            subgroups.sort((a, b) => Math.abs(b.effect) - Math.abs(a.effect));

            // Display results
            const resultsDiv = document.createElement('div');
            resultsDiv.className = 'card';
            resultsDiv.innerHTML = `
                <div class="card-header">
                    <div class="card-title">
                        <div class="card-title-icon">ML</div>
                        ML-Detected Treatment Effect Subgroups
                    </div>
                    <span class="badge badge-info">${subgroups.length} subgroups</span>
                </div>
                <div class="alert alert-info">
                    Machine learning (decision tree) identified patient subgroups with heterogeneous treatment effects.
                    Larger |effect| indicates stronger treatment response or resistance.
                </div>
                <div class="data-table-container">
                    <table class="results-table">
                        <thead>
                            <tr>
                                <th>Subgroup Definition</th>
                                <th>N</th>
                                <th>Treatment Effect</th>
                                <th>Effect Direction</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${subgroups.map(sg => `
                                <tr>
                                    <td style="max-width: 400px;">${sg.path || 'Overall'}</td>
                                    <td>${sg.n}</td>
                                    <td>${sg.effect ? sg.effect.toFixed(3) : 'N/A'}</td>
                                    <td>
                                        ${sg.effect < -0.1 ? '<span class="badge badge-success">Benefit</span>' :
                                          sg.effect > 0.1 ? '<span class="badge badge-danger">Harm</span>' :
                                          '<span class="badge badge-secondary">Neutral</span>'}
                                    </td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                </div>
            `;

            // Add to results panel
            const resultsPanel = document.getElementById('panel-results');
            if (resultsPanel) {
                const existing = resultsPanel.querySelector('.ml-subgroup-results');
                if (existing) existing.remove();
                resultsDiv.classList.add('ml-subgroup-results');
                resultsPanel.appendChild(resultsDiv);
            }

            showNotification(`Found ${subgroups.length} treatment effect subgroups`, 'success');
            return subgroups;
        }

        // ============================================================
        // MULTIPLE IMPUTATION FOR MISSING DATA
        // ============================================================

        function performMultipleImputation(numImputations = 5) {
            if (!APP.data || APP.data.length === 0) {
                showNotification('Please load data first', 'warning');
                return;
            }

            // Identify columns with missing data
            const columns = Object.keys(APP.data[0]);
            const missingCols = columns.filter(col => APP.data.some(d => d[col] == null || d[col] === '' || (typeof d[col] === 'number' && isNaN(d[col]))));

            if (missingCols.length === 0) {
                showNotification('No missing data detected', 'info');
                return APP.data;
            }

            // Perform simple imputation (mean/mode imputation as baseline)
            const imputedDatasets = [];

            for (let m = 0; m < numImputations; m++) {
                const imputed = JSON.parse(JSON.stringify(APP.data));

                missingCols.forEach(col => {
                    const nonMissing = APP.data.filter(d => d[col] != null && d[col] !== '' && !(typeof d[col] === 'number' && isNaN(d[col]))).map(d => d[col]);

                    if (nonMissing.length === 0) return;

                    // Check if numeric or categorical
                    const isNumeric = typeof nonMissing[0] === 'number';

                    imputed.forEach(d => {
                        if (d[col] == null || d[col] === '' || (typeof d[col] === 'number' && isNaN(d[col]))) {
                            if (isNumeric) {
                                // Mean imputation with random noise
                                const mean = nonMissing.reduce((a, b) => a + b, 0) / nonMissing.length;
                                const sd = Math.sqrt(nonMissing.reduce((a, b) => a + (b - mean) ** 2, 0) / nonMissing.length);
                                // Add random noise from normal distribution (Box-Muller)
                                const u1 = Math.random(), u2 = Math.random();
                                const noise = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2) * sd * 0.1;
                                d[col] = mean + noise;
                            } else {
                                // Mode imputation with random sampling
                                const counts = {};
                                nonMissing.forEach(v => counts[v] = (counts[v] || 0) + 1);
                                const modes = Object.entries(counts).sort((a, b) => b[1] - a[1]);
                                // Random sample from top modes
                                const topModes = modes.slice(0, Math.min(3, modes.length));
                                d[col] = topModes[Math.floor(Math.random() * topModes.length)][0];
                            }
                        }
                    });
                });

                imputedDatasets.push(imputed);
            }

            // Store imputed datasets
            APP.imputedData = imputedDatasets;

            showNotification(`Created ${numImputations} imputed datasets for ${missingCols.length} variables with missing data`, 'success');

            // Update Guardian panel
            const qualityBadge = document.getElementById('qualityBadge');
            if (qualityBadge) {
                qualityBadge.textContent = 'IMPUTED';
                qualityBadge.className = 'badge badge-info';
            }

            return imputedDatasets;
        }

        // ============================================================
        // IPD + AGGREGATE DATA SYNTHESIS
        // ============================================================

        // Store aggregate data separately
        APP.aggregateData = [];

        // Add aggregate data from published studies
        function addAggregateData(studyId, effect, se, n, nEvents = null) {
            const ci = MetaAnalysis.confidenceInterval(effect, se, 0.95);

            APP.aggregateData.push({
                study: studyId,
                effect: effect,
                se: se,
                variance: se * se,
                n: n,
                events: nEvents,
                lower: ci.lower,
                upper: ci.upper,
                source: 'aggregate',
                weight: 1 / (se * se)
            });

            showNotification(`Added aggregate data: ${studyId}`, 'success');
            return APP.aggregateData;
        }

        // Combined IPD + AD meta-analysis
        function runCombinedIPDADAnalysis() {
            if ((!APP.data || APP.data.length === 0) && APP.aggregateData.length === 0) {
                showNotification('Please load IPD or add aggregate data first', 'warning');
                return;
            }

            let allStudyResults = [];

            // Process IPD data (if available)
            if (APP.data && APP.data.length > 0) {
                const studyVar = APP.config.studyVar || 'study_id';
                const treatmentVar = APP.config.treatmentVar || 'treatment';
                const eventVar = APP.config.eventVar || 'event';

                const studies = [...new Set(APP.data.map(d => d[studyVar]))];

                studies.forEach(studyId => {
                    const studyData = APP.data.filter(d => d[studyVar] === studyId);
                    const treat1 = studyData.filter(d => d[treatmentVar] === 1);
                    const treat0 = studyData.filter(d => d[treatmentVar] === 0);

                    if (treat1.length < 5 || treat0.length < 5) return;

                    // Binary outcome: log odds ratio
                    const a = treat1.filter(d => d[eventVar] === 1).length;
                    const b = treat1.length - a;
                    const c = treat0.filter(d => d[eventVar] === 1).length;
                    const d = treat0.length - c;

                    const effect = Math.log((a + 0.5) * (d + 0.5) / ((b + 0.5) * (c + 0.5)));
                    const variance = 1 / (a + 0.5) + 1 / (b + 0.5) + 1 / (c + 0.5) + 1 / (d + 0.5);
                    const se = Math.sqrt(variance);

                    allStudyResults.push({
                        study: studyId,
                        effect: effect,
                        se: se,
                        variance: variance,
                        n: studyData.length,
                        events: a + c,
                        source: 'IPD',
                        weight: 1 / variance
                    });
                });
            }

            // Add aggregate data
            APP.aggregateData.forEach(ad => {
                allStudyResults.push({ ...ad });
            });

            if (allStudyResults.length === 0) {
                showNotification('No valid study results to pool', 'warning');
                return;
            }

            // Perform random-effects meta-analysis
            const effects = allStudyResults.map(s => s.effect);
            const variances = allStudyResults.map(s => s.variance);

            const pooled = MetaAnalysis.randomEffects(effects, variances, 'REML');

            // Store combined results
            APP.combinedResults = {
                studies: allStudyResults,
                pooled: pooled,
                nIPD: allStudyResults.filter(s => s.source === 'IPD').length,
                nAD: allStudyResults.filter(s => s.source === 'aggregate').length
            };

            // Update results display
            const displayEffect = Math.exp(pooled.pooled);
            const displayCI = `${Math.exp(pooled.pooled - 1.96 * pooled.se).toFixed(2)}-${Math.exp(pooled.pooled + 1.96 * pooled.se).toFixed(2)}`;

            showNotification(`Combined ${APP.combinedResults.nIPD} IPD studies + ${APP.combinedResults.nAD} AD studies. Pooled OR: ${displayEffect.toFixed(2)} (${displayCI})`, 'success');

            return APP.combinedResults;
        }

